sys_script_include.script:
var HistoryList = Class.create();
HistoryList.prototype = {
    initialize: function (options) {
        this.transactionId = options?.transactionId || gs.generateGUID();
        this.logger = new Logger({
            transactionId: this.transactionId,
            source: this.type,
            includeTimeStamp: true,
            includeUserInfo: true,
            includeSessionId: true,
        });

        this.navigatorHistory = new NavigatorHistory({
            transactionId: this.transactionId,
        });
    },

    getPageTitle: function () {
        return "";
    },

    canCreate: function () {
        return false;
    },

    canFilter: function () {
        return false;
    },

    canSavePreferences: function () {
        return false;
    },

    canConfigureColumns: function () {
        return false;
    },

    getAllAvailableColumns: function () {
        return this.getDefaultColumns();
    },

    getAppliedFiltersInfoMessage: function () {
        return "";
    },

    getBreadcrumbs: function () {
        return [];
    },

    getChoiceValues: function () {
        return [];
    },

    getDefaultColumns: function () {
        return [
            { name: "title", label: "", default: true },
            { name: "lastAccessed", label: "", default: true },
        ];
    },

    getDetailViewPage: function () {
        return "";
    },

    getFilterFields: function () {
        return [];
    },

    getIdField: function () {
        return "url";
    },

    getPrimaryCellClickAction: function () {
        return {
            type: "link",
            urlField: "url",
        };
    },

    getCellContent: function (field, record) {
        if (field.name === "title") {
            return {
                layout: "stack",
                blocks: [
                    { value: record.title || "" },
                    {
                        value: record.subtitle || "",
                        className: "scm-table-cell-muted",
                    },
                ],
            };
        }

        if (field.name === "lastAccessed") {
            return {
                layout: "stack",
                blocks: [{ value: record.lastAccessed || "" }],
            };
        }

        return {
            layout: "stack",
            blocks: [{ value: record[field.name] || "" }],
        };
    },

    getHistoryEntries: function () {
        try {
            return this.navigatorHistory
                .getHistoryEntries()
                .map(function (entry) {
                    return {
                        url: entry.url,
                        title: entry.title || entry.url,
                        subtitle: entry.subtitle || "",
                        lastAccessed: entry.lastAccessed || "",
                    };
                });
        } catch (error) {
            this.logger.error({
                method: "getHistoryEntries",
                message: "Error getting history entries",
                error: error.message,
            });
            return [];
        }
    },

    getOrderBy: function () {
        return "lastAccessed";
    },

    getOrderDirection: function () {
        return "DESC";
    },

    getTableColumns: function () {
        return this.getDefaultColumns();
    },

    getTableData: function () {
        return this.getHistoryEntries();
    },

    getTableLimit: function () {
        return 10;
    },

    getTotalRecords: function () {
        return this.getHistoryEntries().length;
    },

    showAppliedFilters: function () {
        return false;
    },

    showTableMetadata: function () {
        return false;
    },

    type: "HistoryList",
};
